#include <bits/stdc++.h>
using namespace std;
const int N=50005;
int n,m,a[N],block,ans1[N],ans2[N],vis[N],anss;
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,id;
	bool operator<(const node other) const
	{
		if(fun(l)!=fun(other.l)) return fun(l)<fun(other.l);
		return r<other.r;
	}
} q[N];
void add(int val)
{
	anss-=(vis[val]*(vis[val]-1)/2);
	vis[val]++;
	anss+=(vis[val]*(vis[val]-1)/2);
}
void del(int val)
{
	anss-=(vis[val]*(vis[val]-1)/2);
	vis[val]--;
	anss+=(vis[val]*(vis[val]-1)/2);
}
int main()
{
	cin>>n>>m;
	block=sqrt(n);
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=m;i++)
	{
		cin>>q[i].l>>q[i].r;
		q[i].id=i;
	}
	sort(q+1,q+1+m);
	int l=1,r=0;
	for(int i=1;i<=m;i++)
	{
		int ll=q[i].l,rr=q[i].r;
		if(ll==rr)
		{
			ans2[q[i].id]=1;
			continue;
		}
		while(l<ll)
		{
			del(a[l++]);
		}
		while(l>ll)
		{
			add(a[--l]);
		}
		while(r<rr)
		{
			add(a[++r]);
		}
		while(r>rr)
		{
			del(a[r--]);
		}
		ans1[q[i].id]=anss;
		ans2[q[i].id]=(1ll*(rr-ll+1)*(rr-ll)/2);
		int tmp=__gcd(ans1[q[i].id],ans2[q[i].id]);
		ans1[q[i].id]/=tmp;
		ans2[q[i].id]/=tmp;
	}
	for(int i=1;i<=m;i++)
	{
		cout<<ans1[i]<<"/"<<ans2[i]<<"\n";
	}
	return 0;
}
